clear; close all; clc;

%% Plot_single_ring_qpm_result.m
% Select one saved .mat result generated by run_ring_qpm_case and plot it.

project_root = fileparts(fileparts(mfilename('fullpath')));
addpath(fullfile(project_root,'functions'));
addpath(fullfile(project_root,'plotting'));

default_result_dir = fullfile(project_root,'results');
if ~exist(default_result_dir,'dir'), default_result_dir = project_root; end

[file,path] = uigetfile({'*.mat','MAT-files (*.mat)'}, ...
    'Select one RingQPM result file', ...
    fullfile(default_result_dir, filesep));
if isequal(file,0)
    fprintf('No file selected.\n');
    return;
end

result_file = fullfile(path,file);
fprintf('Loading result:\n%s\n', result_file);
S = load(result_file);
if ~isfield(S,'out')
    error('Selected file does not contain variable "out".');
end

plot_opts = struct();

% ---- post-processing wavelength range ----
% Fundamental wavelength range in nm.
% [] means use full saved range.
% plot_opts.lambda_IR_range_nm = [1470, 1630];
plot_opts.lambda_IR_range_nm = [];

% ---- post-processing center ----
% Fundamental center wavelength in nm.
% [] means use out.scan.lambda0_IR.
plot_opts.center_lambda_IR_nm = 1550;

% Recompute ng/Dint/QPM/GVM/mismatch after cropping or changing center.
plot_opts.recompute_after_crop = true;

% 'equiv': SH x-axis = mu_SH/2; 'raw': SH x-axis = mu_SH
plot_opts.SH_mu_axis = 'raw';

plot_ring_qpm_result(S.out, plot_opts);

% Additional figure: GVD of the two wavelength bands.
% Here GVD is plotted as the dispersion parameter
%   D = d(1/v_g)/d(lambda) = (1/c)*d n_g/d lambda
% with unit ps/(nm km).
plot_ring_qpm_gvd(S.out, plot_opts);

%% ============================================================
%  Local plotting helpers
% ============================================================

function plot_ring_qpm_gvd(out, plot_opts)

if nargin < 2
    plot_opts = struct();
end

required_fields = {'lambda_IR','lambda_SH','neff_IR','neff_SH'};
for ii = 1:numel(required_fields)
    if ~isfield(out, required_fields{ii})
        error('out.%s is required for GVD plotting.', required_fields{ii});
    end
end

c0 = 299792458;  % [m/s]

lambda_IR = out.lambda_IR(:);   % [um]
lambda_SH = out.lambda_SH(:);   % [um]
neff_IR   = out.neff_IR(:);
neff_SH   = out.neff_SH(:);

GVD_IR_ps_per_nm_km = calc_gvd_D_from_neff(lambda_IR, neff_IR, c0);
GVD_SH_ps_per_nm_km = calc_gvd_D_from_neff(lambda_SH, neff_SH, c0);

idx_IR_plot = isfinite(lambda_IR) & isfinite(GVD_IR_ps_per_nm_km);
idx_SH_plot = isfinite(lambda_SH) & isfinite(GVD_SH_ps_per_nm_km);

if isfield(plot_opts, 'lambda_IR_range_nm') && ~isempty(plot_opts.lambda_IR_range_nm)
    lambda_IR_range_um = sort(plot_opts.lambda_IR_range_nm(:)) / 1e3;
    idx_IR_plot = idx_IR_plot & ...
        lambda_IR >= lambda_IR_range_um(1) & ...
        lambda_IR <= lambda_IR_range_um(2);

    % The SH wavelength range is tied to the fundamental range by lambda_SH = lambda_IR/2.
    idx_SH_plot = idx_SH_plot & ...
        lambda_SH >= lambda_IR_range_um(1)/2 & ...
        lambda_SH <= lambda_IR_range_um(2)/2;
end

x_IR_nm = lambda_IR * 1e3;
x_SH_nm = lambda_SH * 1e3;

select = get_optional_field(out, 'select', struct());
geom   = get_optional_field(out, 'geom',   struct());

IR_label = make_mode_label(select, 'IR');
SH_label = make_mode_label(select, 'SH');

figure('Name', 'GVD of IR and SH bands', ...
    'Color', 'w', 'Position', [240, 120, 880, 620]);

tiledlayout(2, 1, 'TileSpacing', 'compact', 'Padding', 'compact');

nexttile;
plot(x_IR_nm(idx_IR_plot), GVD_IR_ps_per_nm_km(idx_IR_plot), 'o-', ...
    'LineWidth', 1.5, 'MarkerSize', 4);
grid on; box on;
xlabel('IR wavelength (nm)');
ylabel('GVD D (ps/(nm km))');
title(sprintf('IR band GVD%s', IR_label));
ylim_auto_margin_local(gca, GVD_IR_ps_per_nm_km(idx_IR_plot), 0.10);
add_center_xline_if_available(gca, out, plot_opts, 'IR');

nexttile;
plot(x_SH_nm(idx_SH_plot), GVD_SH_ps_per_nm_km(idx_SH_plot), 's-', ...
    'LineWidth', 1.5, 'MarkerSize', 4);
grid on; box on;
xlabel('SH wavelength (nm)');
ylabel('GVD D (ps/(nm km))');
title(sprintf('SH band GVD%s', SH_label));
ylim_auto_margin_local(gca, GVD_SH_ps_per_nm_km(idx_SH_plot), 0.10);
add_center_xline_if_available(gca, out, plot_opts, 'SH');

if isfield(geom, 'Radius')
    sgtitle(sprintf('Group-velocity dispersion, R = %.1f \\mum', geom.Radius), ...
        'Interpreter', 'tex', 'FontWeight', 'normal');
else
    sgtitle('Group-velocity dispersion', ...
        'Interpreter', 'tex', 'FontWeight', 'normal');
end

end

function GVD_ps_per_nm_km = calc_gvd_D_from_neff(lambda_um, neff, c0)
%CALC_GVD_D_FROM_NEFF Calculate the dispersion parameter D from neff(lambda).
%
% Definition used here:
%   n_g = n_eff - lambda * dn_eff/dlambda
%   D   = d(1/v_g)/dlambda = (1/c) * dn_g/dlambda
%
% lambda is in um, so the conversion is:
%   D [ps/(nm km)] = (dn_g/dlambda_um) * 1e12 / c0

lambda_um = lambda_um(:);
neff      = neff(:);

GVD_ps_per_nm_km = nan(size(lambda_um));

valid = isfinite(lambda_um) & isfinite(neff);
if sum(valid) < 5
    warning('Too few valid neff points for GVD calculation.');
    return;
end

lambda_v = lambda_um(valid);
neff_v   = neff(valid);

[lambda_v, sort_idx] = sort(lambda_v);
neff_v = neff_v(sort_idx);

[lambda_u, unique_idx] = unique(lambda_v, 'stable');
neff_u = neff_v(unique_idx);

if numel(lambda_u) < 5
    warning('Too few unique wavelength points for GVD calculation.');
    return;
end

% PCHIP keeps the curve shape and avoids artificial oscillations.
neff_smooth = interp1(lambda_u, neff_u, lambda_u, 'pchip', 'extrap');

dneff_dlambda_um = gradient(neff_smooth, lambda_u);
ng_u = neff_smooth - lambda_u .* dneff_dlambda_um;

dng_dlambda_um = gradient(ng_u, lambda_u);

GVD_u_ps_per_nm_km = dng_dlambda_um * 1e12 / c0;

% Map the GVD values back to the original wavelength ordering.
GVD_ps_per_nm_km(valid) = interp1(lambda_u, GVD_u_ps_per_nm_km, ...
    lambda_um(valid), 'pchip', 'extrap');

end

function value = get_optional_field(S, field_name, default_value)

if isstruct(S) && isfield(S, field_name)
    value = S.(field_name);
else
    value = default_value;
end

end

function label = make_mode_label(select, band_name)

label = '';

if ~isstruct(select) || ~isfield(select, band_name)
    return;
end

mode_info = select.(band_name);

if isfield(mode_info, 'pol') && isfield(mode_info, 'order')
    label = sprintf(', %s%d', upper(mode_info.pol), mode_info.order - 1);
end

end

function add_center_xline_if_available(ax, out, plot_opts, band_name)

center_lambda_IR_nm = [];

if isfield(plot_opts, 'center_lambda_IR_nm') && ~isempty(plot_opts.center_lambda_IR_nm)
    center_lambda_IR_nm = plot_opts.center_lambda_IR_nm;
elseif isfield(out, 'scan') && isfield(out.scan, 'lambda0_IR')
    center_lambda_IR_nm = out.scan.lambda0_IR * 1e3;
end

if isempty(center_lambda_IR_nm) || ~isfinite(center_lambda_IR_nm)
    return;
end

switch upper(band_name)
    case 'IR'
        x0_nm = center_lambda_IR_nm;
    case 'SH'
        x0_nm = center_lambda_IR_nm / 2;
    otherwise
        return;
end

xline(ax, x0_nm, '--');

end

function ylim_auto_margin_local(ax, y, margin_frac)

y = y(:);
y = y(isfinite(y));

if isempty(y)
    return;
end

ymin = min(y);
ymax = max(y);

if ymax == ymin
    dy = max(abs(ymax), 1) * 0.05;
else
    dy = (ymax - ymin) * margin_frac;
end

ylim(ax, [ymin - dy, ymax + dy]);

end
